#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <stddef.h>

#define CANARY 0xDEADBEEF

typedef struct {
    uint32_t front_canary;
    size_t size;
    char data[];  /* flexible array member */
} GuardedBlock;

void *guarded_alloc(size_t size) {
    GuardedBlock *blk = malloc(sizeof(GuardedBlock) + size + sizeof(uint32_t));
    if (!blk) return NULL;
    blk->front_canary = CANARY;
    blk->size = size;
    uint32_t *back = (uint32_t *)(blk->data + size);
    *back = CANARY;
    return blk->data;
}

int guarded_check(void *ptr) {
    GuardedBlock *blk = (GuardedBlock *)((char *)ptr - offsetof(GuardedBlock, data));
    if (blk->front_canary != CANARY) return -1;
    uint32_t *back = (uint32_t *)(blk->data + blk->size);
    if (*back != CANARY) return -2;
    return 0;
}

void guarded_free(void *ptr) {
    GuardedBlock *blk = (GuardedBlock *)((char *)ptr - offsetof(GuardedBlock, data));
    free(blk);
}

int main(void) {
    char *buf = guarded_alloc(8);
    if (!buf) return 1;
    strcpy(buf, "OK");
    printf("Check apres ecriture normale : %d\n", guarded_check(buf));

    char *buf2 = guarded_alloc(4);
    if (!buf2) { guarded_free(buf); return 1; }
    strcpy(buf2, "ABCDEFGH"); /* overflow! 9 bytes > 4 */
    printf("Check apres overflow : %d\n", guarded_check(buf2));

    guarded_free(buf);
    guarded_free(buf2);
    printf("Canary : 0x%X\n", CANARY);
    return 0;
}

